import { Component, EventEmitter, Input, Output } from '@angular/core';

export interface User{
  name:string;
  age:number;
  city:string;
}

@Component({
  selector: 'app-child',
  templateUrl: './child.component.html',
  styleUrls: ['./child.component.scss']
})
export class ChildComponent {
  @Input() userMessage = ''
  @Input() user!:User;


}
<h3>Child Component</h3>
<p><strong>Simple message: </strong>{{userMessage}}</p>

<p><strong>User Name received from Parent:</strong> {{user.name}}</p>
<p><strong>User Age received from Parent:</strong> {{user.age}}</p>
<p><strong>User City received from Parent:</strong> {{user.city}}</p>
